source = DATA_PATH.read_text(encoding="utf-8")

for slug, intro in INTROS.items():
    pattern = rf'("{re.escape(slug)}": \{{.*?"intro": )"[^"]*"'
    repl = rf'\1"{intro}"'
    new_source, n = re.subn(pattern, repl, source, count=1, flags=re.DOTALL)
    if n != 1:
        print(f"FAIL: {slug}")
    else:
        source = new_source
        print(f"OK: {slug}")

DATA_PATH.write_text(source, encoding="utf-8")
print("Done.")
